import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [data, setData] = useState([]);

  const fetchData = async () => {
    const res = await fetch("http://localhost:8000/incidents");
    const json = await res.json();
    setData(json);
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={page}>
      <h2>🚨 Incident Dashboard</h2>

      <div style={grid}>
        {data.map((i) => (
          <div
            key={i.id}
            style={card}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-6px)";
              e.currentTarget.style.boxShadow =
                "0 10px 25px rgba(0,0,0,0.15)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "none";
              e.currentTarget.style.boxShadow =
                "0 4px 12px rgba(0,0,0,0.08)";
            }}
          >
            <h3>{i.component_id}</h3>
            <p>Incident #{i.id}</p>

            <span style={badge(i.severity)}>{i.severity}</span>

            <p>Status: {i.status}</p>
            <p>Signals: {i.signal_count}</p>
            <p>{new Date(i.start_time).toLocaleString()}</p>

            <Link to={`/incident/${i.id}`} style={btn}>
              View Details →
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}

//
// 🎨 STYLES (Minimal upgrade only)
//

const page = {
  padding: "20px",
  fontFamily: "Segoe UI",
  background: "#f5f7fa",
  minHeight: "100vh"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
  gap: "20px"
};

const card = {
  background: "#fff",
  padding: "18px",
  borderRadius: "12px",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
  transition: "all 0.25s ease"
};

const badge = (s) => ({
  padding: "4px 10px",
  borderRadius: "8px",
  color: "#fff",
  display: "inline-block",
  marginBottom: "8px",
  background:
    s === "P0"
      ? "#d32f2f"
      : s === "P1"
      ? "#f57c00"
      : s === "P2"
      ? "#fbc02d"
      : "#388e3c"
});

const btn = {
  display: "inline-block",
  marginTop: "10px",
  padding: "6px 10px",
  background: "#2f6fed",
  color: "#fff",
  borderRadius: "6px",
  textDecoration: "none"
};
